package modules.monitoring.org.apache.airavata.monitoring;

public class Util { public static MailConfig getMailConfig ( ) throws ApplicationSettingsException { MailConfig mailConfig = new MailConfig ( ) ; mailConfig . setHost ( "smtp.gmail.com" ) ; mailConfig . setUser ( "test.airavata@gmail.com" ) ; mailConfig . setPassword ( "airavata" ) ; mailConfig . setStoreProtocol ( "imaps" ) ; mailConfig . setFolder ( "inbox" ) ; mailConfig . setPollingInterval ( 1000 ) ; return mailConfig ; } public static Properties getBrokerProperties ( ) { Properties props = new Properties ( ) ; props . setProperty ( "monitor.email.exchange.name" , "monitor" ) ; props . setProperty ( "monitor.email.broker.URI" , "amqp://localhost:5672" ) ; props . setProperty ( "monitor.email.broker.queue1.name" , "q1" ) ; props . setProperty ( "monitor.email.broker.queue2.name" , "q2" ) ; return props ; } }